// Classe genérica: Caixa<T> funciona pra qualquer tipo, com segurança de tipo em compile-time
public class Caixa<T> {
    private T conteudo;

    public void guardar(T item) { this.conteudo = item; }
    public T pegar() { return conteudo; }
}

Caixa<String> caixaDeTexto = new Caixa<>();
caixaDeTexto.guardar("documento");
String valor = caixaDeTexto.pegar(); // sem cast manual — o compilador já sabe que é String

// Bounded type: T precisa implementar Comparable<T> para o método funcionar
public static <T extends Comparable<T>> T maior(T a, T b) {
    return a.compareTo(b) > 0 ? a : b;
}

