public Optional<User> buscarPorId(Long id) {
    return userRepository.findById(id); // Spring Data JPA já retorna Optional
}

// Uso idiomático: encadeando map + orElse, sem if/else explícito
String nome = buscarPorId(1L)
    .map(User::getName)
    .orElse("Anônimo");

// ifPresent: executa uma ação só se o valor existir
buscarPorId(1L).ifPresent(u -> System.out.println("Encontrado: " + u.getName()));

// orElseThrow: lança exceção customizada quando não há valor
User user = buscarPorId(1L)
    .orElseThrow(() -> new UserNotFoundException(1L));

