// Record com validação no construtor compacto — não existe PedidoDTO com valor negativo
public record PedidoDTO(Long id, BigDecimal valor, StatusPedido status) {
    public PedidoDTO { // construtor compacto: sem repetir os parâmetros
        if (valor.compareTo(BigDecimal.ZERO) < 0) {
            throw new IllegalArgumentException("Valor não pode ser negativo");
        }
    }
}

// Sealed interface: só essas 3 classes podem implementar ResultadoPagamento
public sealed interface ResultadoPagamento
    permits Aprovado, Recusado, Pendente {}

public record Aprovado(String txId) implements ResultadoPagamento {}
public record Recusado(String motivo) implements ResultadoPagamento {}
public record Pendente(LocalDateTime expiraEm) implements ResultadoPagamento {}

// Pattern matching exaustivo: o compilador GARANTE que todo caso foi tratado
String mensagem = switch (resultado) {
    case Aprovado a -> "OK: " + a.txId();
    case Recusado r -> "Falhou: " + r.motivo();
    case Pendente p -> "Aguardando até " + p.expiraEm();
    // sem default — e não precisa, o compilador sabe que não sobra mais nenhum caso
};

