// Sem sealed, um switch sobre uma interface comum PRECISA de default,
// mesmo que você (acredite) ter coberto todos os casos reais
public interface ResultadoPagamento {}
public record Aprovado(String txId) implements ResultadoPagamento {}
public record Recusado(String motivo) implements ResultadoPagamento {}

String mensagem = switch (resultado) {
    case Aprovado a -> "OK: " + a.txId();
    case Recusado r -> "Falhou: " + r.motivo();
    default -> throw new IllegalStateException("Caso inesperado"); // precisa existir
};
// Se alguém criar uma nova classe implementando ResultadoPagamento (ex: Pendente),
// o compilador NÃO avisa. O erro só aparece em runtime, quando cair no default.
